Class.combo_button_class:
height={stretch} width={auto} margin={1,0,0,0} padding={1,0,0,0} border_size={1,0,0,0} valign={center} 
                                            hot_border_color={combo_hot_border} 
                                            pushed_border_color={combo_hot_border}
                                            hot_color={combo_btn_hot} 
                                            pushed_color={combo_btn_push} 
                                            normal_image={file='public/combo/arrow_normal.svg' valign='center'} 
                                            hot_image={file='public/combo/arrow_hot.svg' valign='center'}

Class.dropbox_item_class:
width={stretch} height={24} text_padding={20,0,2,1} text_align={left,vcenter} 
                                                  normal_image={file='public/checkbox/checkbox-outline-unchecked.svg' valign='center'} 
                                                  selected_normal_image={file='public/checkbox/checkbox-outline-checked.svg' valign='center'}

Class.left_button_class:
height={stretch} width={stretch} padding={0,0,1,0} border_size={0,0,1,0} valign={center} 
                                                  hot_border_color={combo_hot_border} 
                                                  pushed_border_color={combo_hot_border}                                                   
                                                  hot_color={combo_btn_hot} 
                                                  pushed_color={combo_btn_push}

Class.right_button_class:
height={stretch} width={auto} padding={1,0,0,0} border_size={1,0,0,0} valign={center} 
                                                   hot_border_color={combo_hot_border} 
                                                   pushed_border_color={combo_hot_border}                                                    
                                                   hot_color={combo_btn_hot} 
                                                   pushed_color={combo_btn_push} 
                                                   normal_image={file='public/combo/arrow_normal.svg' valign='center'} 
                                                   hot_image={file='public/combo/arrow_hot.svg' valign='center'}
